operation.add:
// JSON-LD Organization Schema
$schema = array(
	'@context' => 'https://schema.org',
	'@type' => 'Organization',
	'name' => $this->config->get('config_name'),
	'url' => HTTPS_SERVER,
	'logo' => HTTPS_SERVER . 'image/' . $this->config->get('config_logo'),
	'telephone' => $this->config->get('config_telephone'),
	'email' => $this->config->get('config_email'),
	'address' => array(
		'@type' => 'PostalAddress',
		'addressLocality' => 'Казахстан',
		'addressCountry' => 'KZ'
	),
	'contactPoint' => array(
		'@type' => 'ContactPoint',
		'telephone' => $this->config->get('config_telephone'),
		'contactType' => 'sales'
	)
);
$data['schema_organization'] = json_encode($schema, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

// JSON-LD WebSite Schema with SearchAction
$schema_website = array(
	'@context' => 'https://schema.org',
	'@type' => 'WebSite',
	'name' => $this->config->get('config_name'),
	'url' => HTTPS_SERVER,
	'potentialAction' => array(
		'@type' => 'SearchAction',
		'target' => array(
			'@type' => 'EntryPoint',
			'urlTemplate' => HTTPS_SERVER . 'index.php?route=product/search&search={search_term_string}'
		),
		'query-input' => 'required name=search_term_string'
	)
);
$data['schema_website'] = json_encode($schema_website, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

// JSON-LD Product Schema
$schema_product = array(
	'@context' => 'https://schema.org',
	'@type' => 'Product',
	'name' => $product_info['name'],
	'image' => $data['popup'] ? $data['popup'] : '',
	'description' => strip_tags(html_entity_decode($product_info['meta_description'] ? $product_info['meta_description'] : $product_info['description'], ENT_QUOTES, 'UTF-8')),
	'sku' => $product_info['sku'],
	'mpn' => $product_info['model'],
	'model' => $product_info['model'],
	'brand' => $product_info['manufacturer'] ? array('@type' => 'Brand', 'name' => $product_info['manufacturer']) : null,
	'category' => $category_info ? $category_info['name'] : '',
	'offers' => array(
		'@type' => 'Offer',
		'url' => $this->url->link('product/product', 'product_id=' . $product_info['product_id']),
		'priceCurrency' => $this->session->data['currency'],
		'price' => $product_info['special'] ? $product_info['special'] : $product_info['price'],
		'priceValidUntil' => date('Y-12-31', strtotime('+1 year')),
		'availability' => $product_info['quantity'] > 0 ? 'https://schema.org/InStock' : 'https://schema.org/OutOfStock'
	)
);
if ($product_info['rating'] > 0) {
	$schema_product['aggregateRating'] = array(
		'@type' => 'AggregateRating',
		'ratingValue' => $product_info['rating'],
		'reviewCount' => $product_info['reviews']
	);
}
$data['schema_product'] = json_encode($schema_product, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

// JSON-LD BreadcrumbList
$schema_breadcrumbs = array();
foreach ($data['breadcrumbs'] as $i => $crumb) {
	$schema_breadcrumbs[] = array(
		'@type' => 'ListItem',
		'position' => $i + 1,
		'name' => strip_tags($crumb['text']),
		'item' => $crumb['href']
	);
}
$data['schema_breadcrumb'] = json_encode(array(
	'@context' => 'https://schema.org',
	'@type' => 'BreadcrumbList',
	'itemListElement' => $schema_breadcrumbs
), JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

// JSON-LD BreadcrumbList
$schema_breadcrumbs = array();
foreach ($data['breadcrumbs'] as $i => $crumb) {
	$schema_breadcrumbs[] = array(
		'@type' => 'ListItem',
		'position' => $i + 1,
		'name' => strip_tags($crumb['text']),
		'item' => $crumb['href']
	);
}
$data['schema_breadcrumb'] = json_encode(array(
	'@context' => 'https://schema.org',
	'@type' => 'BreadcrumbList',
	'itemListElement' => $schema_breadcrumbs
), JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

// JSON-LD BreadcrumbList
$schema_breadcrumbs = array();
foreach ($data['breadcrumbs'] as $i => $crumb) {
	$schema_breadcrumbs[] = array(
		'@type' => 'ListItem',
		'position' => $i + 1,
		'name' => strip_tags($crumb['text']),
		'item' => $crumb['href']
	);
}
$data['schema_breadcrumb'] = json_encode(array(
	'@context' => 'https://schema.org',
	'@type' => 'BreadcrumbList',
	'itemListElement' => $schema_breadcrumbs
), JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
